import React, { useState, useEffect } from 'react';
import {
  View,
  StyleSheet,
  FlatList,
  TouchableOpacity,
} from 'react-native';
import { Text, Card, Searchbar, Chip, FAB } from 'react-native-paper';
import { MaterialCommunityIcons as Icon } from '@expo/vector-icons';
import AsyncStorage from '@react-native-async-storage/async-storage';

export default function ProductListScreen({ navigation }) {
  const [searchQuery, setSearchQuery] = useState('');
  const [products, setProducts] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [userType, setUserType] = useState(null);

  useEffect(() => {
    loadProducts();
    checkUserType();
  }, []);

  const checkUserType = async () => {
    const type = await AsyncStorage.getItem('userType');
    setUserType(type);
  };

  const loadProducts = async () => {
    try {
      const { getProducts } = require('../services/api');
      const data = await getProducts();

      // Map backend Workshops to frontend Products
      const mappedProducts = data.map(workshop => ({
        id: workshop._id,
        name: workshop.title,
        category: workshop.category,
        price: workshop.fee === 'Free' ? 0 : parseInt(workshop.fee.replace('₹', '')),
        unit: 'session',
        farmer: workshop.trainerName || 'Village Trainer',
        location: `${workshop.district || ''}, ${workshop.state || ''}`,
        stock: workshop.maxParticipants - workshop.enrolledCount,
        image: workshop.image || '🎨',
        rating: workshop.rating || 0,
        organic: workshop.skillLevel === 'Beginner'
      }));

      setProducts(mappedProducts);
    } catch (err) {
      console.error('Error loading workshops:', err);
    }
  };

  const categories = ['All', 'Vegetables', 'Fruits', 'Grains', 'Dairy'];

  const filteredProducts = products.filter((product) => {
    const matchesSearch =
      product.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      product.farmer.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory =
      selectedCategory === 'All' || product.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const renderProduct = ({ item }) => (
    <Card
      style={styles.productCard}
      onPress={() => navigation.navigate('ProductDetail', { product: item })}
    >
      <View style={styles.productContent}>
        <View style={styles.productImage}>
          <Text style={styles.productEmoji}>{item.image}</Text>
          {item.organic && (
            <View style={styles.organicBadge}>
              <Text style={styles.organicText}>🌱</Text>
            </View>
          )}
        </View>
        <View style={styles.productInfo}>
          <Text style={styles.productName}>{item.name}</Text>
          <View style={styles.farmerInfo}>
            <Icon name="account" size={14} color="#666" />
            <Text style={styles.farmerName}> {item.farmer}</Text>
          </View>
          <View style={styles.locationInfo}>
            <Icon name="map-marker" size={14} color="#666" />
            <Text style={styles.location}> {item.location}</Text>
          </View>
          <View style={styles.bottomInfo}>
            <View style={styles.ratingContainer}>
              <Icon name="star" size={14} color="#FFC107" />
              <Text style={styles.rating}> {item.rating}</Text>
            </View>
            <Text style={styles.stock}>
              Stock: {item.stock} {item.unit}
            </Text>
          </View>
        </View>
        <View style={styles.priceContainer}>
          <Text style={styles.price}>₹{item.price}</Text>
          <Text style={styles.unit}>/{item.unit}</Text>
          {userType === 'buyer' && (
            <TouchableOpacity style={styles.addButton}>
              <Icon name="cart-plus" size={20} color="#fff" />
            </TouchableOpacity>
          )}
        </View>
      </View>
    </Card>
  );

  return (
    <View style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.headerTitle}>Products</Text>
      </View>

      <Searchbar
        placeholder="Search products or farmers..."
        onChangeText={setSearchQuery}
        value={searchQuery}
        style={styles.searchBar}
      />

      <View style={styles.categoryContainer}>
        <ScrollView horizontal showsHorizontalScrollIndicator={false}>
          {categories.map((category) => (
            <Chip
              key={category}
              selected={selectedCategory === category}
              onPress={() => setSelectedCategory(category)}
              style={styles.categoryChip}
              selectedColor="#2E7D32"
            >
              {category}
            </Chip>
          ))}
        </ScrollView>
      </View>

      <FlatList
        data={filteredProducts}
        renderItem={renderProduct}
        keyExtractor={(item) => item.id.toString()}
        contentContainerStyle={styles.listContainer}
        ListEmptyComponent={
          <View style={styles.emptyContainer}>
            <Icon name="package-variant-closed" size={60} color="#ccc" />
            <Text style={styles.emptyText}>No products found</Text>
          </View>
        }
      />

      {userType === 'farmer' && (
        <FAB
          icon="plus"
          style={styles.fab}
          onPress={() => navigation.navigate('AddProduct')}
          color="#fff"
        />
      )}
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#f5f5f5',
  },
  header: {
    backgroundColor: '#fff',
    padding: 20,
    paddingTop: 60,
    elevation: 2,
  },
  headerTitle: {
    fontSize: 24,
    fontWeight: 'bold',
    color: '#333',
  },
  searchBar: {
    margin: 20,
    marginBottom: 10,
    elevation: 2,
  },
  categoryContainer: {
    paddingHorizontal: 20,
    marginBottom: 15,
  },
  categoryChip: {
    marginRight: 8,
  },
  listContainer: {
    paddingBottom: 20,
  },
  productCard: {
    marginHorizontal: 20,
    marginBottom: 15,
    elevation: 2,
  },
  productContent: {
    flexDirection: 'row',
    padding: 15,
  },
  productImage: {
    width: 80,
    height: 80,
    backgroundColor: '#f0f0f0',
    borderRadius: 8,
    justifyContent: 'center',
    alignItems: 'center',
    position: 'relative',
  },
  productEmoji: {
    fontSize: 50,
  },
  organicBadge: {
    position: 'absolute',
    top: 5,
    right: 5,
    backgroundColor: '#fff',
    borderRadius: 10,
    padding: 2,
  },
  organicText: {
    fontSize: 12,
  },
  productInfo: {
    flex: 1,
    marginLeft: 15,
    justifyContent: 'center',
  },
  productName: {
    fontSize: 16,
    fontWeight: 'bold',
    color: '#333',
    marginBottom: 5,
  },
  farmerInfo: {
    flexDirection: 'row',
    alignItems: 'center',
    marginBottom: 3,
  },
  farmerName: {
    fontSize: 13,
    color: '#666',
  },
  locationInfo: {
    flexDirection: 'row',
    alignItems: 'center',
    marginBottom: 5,
  },
  location: {
    fontSize: 12,
    color: '#666',
  },
  bottomInfo: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
  },
  ratingContainer: {
    flexDirection: 'row',
    alignItems: 'center',
  },
  rating: {
    fontSize: 12,
    color: '#666',
  },
  stock: {
    fontSize: 11,
    color: '#999',
  },
  priceContainer: {
    alignItems: 'flex-end',
    justifyContent: 'center',
  },
  price: {
    fontSize: 20,
    fontWeight: 'bold',
    color: '#2E7D32',
  },
  unit: {
    fontSize: 12,
    color: '#666',
    marginBottom: 10,
  },
  addButton: {
    backgroundColor: '#2E7D32',
    width: 36,
    height: 36,
    borderRadius: 18,
    justifyContent: 'center',
    alignItems: 'center',
  },
  emptyContainer: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    marginTop: 100,
  },
  emptyText: {
    fontSize: 16,
    color: '#999',
    marginTop: 10,
  },
  fab: {
    position: 'absolute',
    margin: 16,
    right: 0,
    bottom: 0,
    backgroundColor: '#2E7D32',
  },
});
